  "inlineSchema": "// ─────────────────────────────────────────────────────────────────────────────\n// Prisma Schema  –  POS System (Home Appliances Shop)\n// ─────────────────────────────────────────────────────────────────────────────\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ── Users ────────────────────────────────────────────────────────────────────\n\nmodel User {\n  id        String   @id @default(cuid())\n  username  String   @unique\n  password  String\n  fullName  String\n  email     String?  @unique\n  role      String   @default(\"CASHIER\")\n  phone     String?\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  sales         Sale[]\n  inventoryLogs InventoryLog[]\n\n  @@map(\"users\")\n}\n\n// ── Categories ───────────────────────────────────────────────────────────────\n\nmodel Category {\n  id          String   @id @default(cuid())\n  name        String   @unique\n  description String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  products Product[]\n\n  @@map(\"categories\")\n}\n\n// ── Brands ───────────────────────────────────────────────────────────────────\n\nmodel Brand {\n  id          String   @id @default(cuid())\n  name        String   @unique\n  description String?\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  products Product[]\n\n  @@map(\"brands\")\n}\n\n// ── Products ─────────────────────────────────────────────────────────────────\n\nmodel Product {\n  id             String   @id @default(cuid())\n  name           String\n  sku            String   @unique\n  barcode        String?  @unique\n  description    String?\n  categoryId     String\n  brandId        String\n  purchasePrice  Float\n  salePrice      Float\n  stock          Int      @default(0)\n  lowStockLimit  Int      @default(5)\n  warrantyMonths Int      @default(0)\n  imageUrl       String?\n  isActive       Boolean  @default(true)\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  category      Category       @relation(fields: [categoryId], references: [id])\n  brand         Brand          @relation(fields: [brandId], references: [id])\n  saleItems     SaleItem[]\n  inventoryLogs InventoryLog[]\n\n  @@map(\"products\")\n}\n\n// ── Customers ────────────────────────────────────────────────────────────────\n\nmodel Customer {\n  id        String   @id @default(cuid())\n  name      String\n  phone     String?\n  email     String?\n  address   String?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  sales Sale[]\n\n  @@map(\"customers\")\n}\n\n// ── Sales ────────────────────────────────────────────────────────────────────\n\nmodel Sale {\n  id            String   @id @default(cuid())\n  invoiceNumber String   @unique\n  cashierId     String\n  customerId    String?\n  subtotal      Float\n  discount      Float    @default(0)\n  tax           Float    @default(0)\n  taxAmount     Float    @default(0)\n  total         Float\n  amountPaid    Float    @default(0)\n  changeGiven   Float    @default(0)\n  paymentMethod String   @default(\"CASH\")\n  notes         String?\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  cashier  User       @relation(fields: [cashierId], references: [id])\n  customer Customer?  @relation(fields: [customerId], references: [id])\n  items    SaleItem[]\n\n  @@map(\"sales\")\n}\n\nmodel SaleItem {\n  id             String  @id @default(cuid())\n  saleId         String\n  productId      String\n  quantity       Int\n  unitPrice      Float\n  discount       Float   @default(0)\n  total          Float\n  serialNumber   String?\n  warrantyMonths Int     @default(0)\n\n  sale    Sale    @relation(fields: [saleId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id])\n\n  @@map(\"sale_items\")\n}\n\n// ── Inventory ────────────────────────────────────────────────────────────────\n\nmodel InventoryLog {\n  id            String   @id @default(cuid())\n  productId     String\n  type          String\n  quantity      Int\n  reason        String?\n  performedById String\n  createdAt     DateTime @default(now())\n\n  product     Product @relation(fields: [productId], references: [id])\n  performedBy User    @relation(fields: [performedById], references: [id])\n\n  @@map(\"inventory_logs\")\n}\n\n// ── Settings ─────────────────────────────────────────────────────────────────\n\nmodel Setting {\n  id        String   @id @default(cuid())\n  key       String   @unique\n  value     String\n  updatedAt DateTime @updatedAt\n\n  @@map(\"settings\")\n}\n",
